+            $replacements += $this->token->generate('menu-link', $menu_tokens, ['menu-link' => $menu_link], $options, $bubbleable_metadata);
+          }
+          else {
+            $url = $node->toUrl();
+            if ($links = $this->menuLinkManager->loadLinksByRoute($url->getRouteName(), $url->getRouteParameters())) {
