+  /**
+   * Implements hook_page_attachments().
+   */
+  #[Hook('page_attachments')]
+  public function pageAttachments() {
+    if ($debug = $this->state->get('token_page_tokens', [])) {
+      $debug += [
+        'tokens' => [],
+        'data' => [],
+        'options' => [],
+      ];
+      foreach (array_keys($debug['tokens']) as $token) {
