-
-  // Attach field tokens to their respective entity tokens.
-  foreach (\Drupal::entityTypeManager()->getDefinitions() as $entity_type_id => $entity_type) {
-    if (!$entity_type->entityClassImplements(ContentEntityInterface::class)) {
